import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import { useTranslation } from 'react-i18next';
import { getUserLocations } from '../utils/api';

const HeaderContainer = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem;
  background-color: ${({ theme }) => theme.colors.background};
  box-shadow: ${({ theme }) => theme.shadows.sm};
  position: sticky;
  top: 0;
  z-index: 10;
  backdrop-filter: blur(8px);

  @media (prefers-color-scheme: dark) {
    background-color: rgba(18, 18, 18, 0.8);
  }

  @media (max-width: 480px) {
    padding: 0.75rem;
  }
`;

const Logo = styled(Link)`
  font-size: ${({ theme }) => theme.fontSizes.xl};
  font-weight: 700;
  color: ${({ theme }) => theme.colors.primary};
  display: flex;
  align-items: center;
  gap: 1.5rem;

  @media (max-width: 480px) {
    font-size: 3.25rem;
    gap: 0.3rem;
  }
`;

const Avatar = styled.img`
  width: 92px;
  height: 92px;
  border-radius: 50%;
  object-fit: cover;
`;

const UserInfo = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: center;
  margin-left: 12px;
`;

const UserName = styled.div`
  font-size: ${({ theme }) => theme.fontSizes.lg};
  font-weight: 600;
  color: ${({ theme }) => theme.colors.text};
`;

const UserUsername = styled.div`
  font-size: ${({ theme }) => theme.fontSizes.sm};
  color: ${({ theme }) => theme.colors.textLight};
`;

const ControlsContainer = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
`;

const LanguageSelector = styled.div`
  position: relative;
  align-self: flex-start;
`;

const LanguageButton = styled.button`
  background: transparent;
  border: 1px solid ${({ theme }) => theme.colors.textLight};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  padding: 0.5rem 1rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: ${({ theme }) => theme.colors.text};
  font-size: ${({ theme }) => theme.fontSizes.sm};

  &:hover {
    background-color: ${({ theme }) => theme.colors.surface};
  }

  @media (prefers-color-scheme: dark) {
    border-color: rgba(255, 255, 255, 0.2);

    &:hover {
      background-color: rgba(255, 255, 255, 0.05);
    }
  }

  @media (max-width: 480px) {
    padding: 0.4rem 0.75rem;
    font-size: 0.8rem;
  }
`;

const LanguageDropdown = styled.div`
  position: absolute;
  top: 100%;
  right: 0;
  margin-top: 0.5rem;
  background-color: ${({ theme }) => theme.colors.background};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  box-shadow: ${({ theme }) => theme.shadows.md};
  overflow: hidden;
  width: 150px;
  z-index: 20;

  @media (prefers-color-scheme: dark) {
    background-color: #1e1e1e;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.3), 0 2px 4px -1px rgba(0, 0, 0, 0.24);
  }

  @media (max-width: 480px) {
    width: 130px;
    right: -5px;
  }
`;

const LanguageOption = styled.button`
  width: 100%;
  text-align: left;
  padding: 0.75rem 1rem;
  background: none;
  border: none;
  color: ${({ theme }) => theme.colors.text};
  font-size: ${({ theme }) => theme.fontSizes.sm};
  cursor: pointer;

  &:hover {
    background-color: ${({ theme }) => theme.colors.surface};
  }

  @media (prefers-color-scheme: dark) {
    &:hover {
      background-color: rgba(255, 255, 255, 0.05);
    }
  }

  @media (max-width: 480px) {
    padding: 0.6rem 0.75rem;
    font-size: 0.8rem;
  }
`;

const LocationSelector = styled.div`
  position: relative;
  align-self: flex-start;
`;

const LocationButton = styled.button`
  background: transparent;
  border: 1px solid ${({ theme }) => theme.colors.textLight};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  padding: 0.5rem 1rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: ${({ theme }) => theme.colors.text};
  font-size: ${({ theme }) => theme.fontSizes.sm};
  width: 100%;

  &:hover {
    background-color: ${({ theme }) => theme.colors.surface};
  }

  @media (prefers-color-scheme: dark) {
    border-color: rgba(255, 255, 255, 0.2);

    &:hover {
      background-color: rgba(255, 255, 255, 0.05);
    }
  }

  @media (max-width: 480px) {
    padding: 0.4rem 0.75rem;
    font-size: 0.8rem;
  }
`;

const LocationDropdown = styled.div`
  position: absolute;
  top: 100%;
  right: 0;
  margin-top: 0.5rem;
  background-color: ${({ theme }) => theme.colors.background};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  box-shadow: ${({ theme }) => theme.shadows.md};
  overflow: hidden;
  width: 180px;
  z-index: 20;

  @media (prefers-color-scheme: dark) {
    background-color: #1e1e1e;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.3), 0 2px 4px -1px rgba(0, 0, 0, 0.24);
  }

  @media (max-width: 480px) {
    width: 150px;
    right: -5px;
  }
`;

const LocationOption = styled.button`
  width: 100%;
  text-align: left;
  padding: 0.75rem 1rem;
  background: none;
  border: none;
  color: ${({ theme }) => theme.colors.text};
  font-size: ${({ theme }) => theme.fontSizes.sm};
  cursor: pointer;

  &:hover {
    background-color: ${({ theme }) => theme.colors.surface};
  }

  @media (prefers-color-scheme: dark) {
    &:hover {
      background-color: rgba(255, 255, 255, 0.05);
    }
  }

  @media (max-width: 480px) {
    padding: 0.6rem 0.75rem;
    font-size: 0.8rem;
  }
`;

const NoLocationsMessage = styled.div`
  padding: 0.75rem 1rem;
  font-size: ${({ theme }) => theme.fontSizes.sm};
  color: ${({ theme }) => theme.colors.textLight};
  text-align: center;
`;

const Header = ({ avatarPath, userData }) => {
  const { t, i18n } = useTranslation();
  const [isLanguageDropdownOpen, setIsLanguageDropdownOpen] = useState(false);
  const [isLocationDropdownOpen, setIsLocationDropdownOpen] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);
  const [userLocations, setUserLocations] = useState([]);
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const languageDropdownRef = useRef(null);
  const locationDropdownRef = useRef(null);

  const changeLanguage = (lng) => {
    i18n.changeLanguage(lng);
    setIsLanguageDropdownOpen(false);
  };

  const fetchUserLocations = async () => {
    if (userData?.user_id) {
      setLoading(true);
      try {
        const locations = await getUserLocations(userData.user_id);
        setUserLocations(locations);

        if (locations.length > 0 && !selectedLocation) {
          setSelectedLocation(locations[0]);
          localStorage.setItem('selectedLocation', JSON.stringify(locations[0]));
        }
      } catch (error) {
        console.error('Error fetching user locations:', error);
      } finally {
        setLoading(false);
      }
    }
  };

  useEffect(() => {
    fetchUserLocations();
  }, [userData]);

  useEffect(() => {
    const savedLocation = localStorage.getItem('selectedLocation');
    if (savedLocation) {
      setSelectedLocation(JSON.parse(savedLocation));
    }
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (languageDropdownRef.current && !languageDropdownRef.current.contains(event.target)) {
        setIsLanguageDropdownOpen(false);
      }

      if (locationDropdownRef.current && !locationDropdownRef.current.contains(event.target)) {
        setIsLocationDropdownOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const selectLocation = (location) => {
    setSelectedLocation(location);
    setIsLocationDropdownOpen(false);
    localStorage.setItem('selectedLocation', JSON.stringify(location));
    navigate('/', { state: { selectedLocation: location } });
  };

  const hasAvatar = Boolean(avatarPath) && avatarPath !== '';
  const logoUrl = '/public/images/logo.jpg';
  const avatarUrl = hasAvatar 
    ? (avatarPath.startsWith('photos/') ? `/telegram/${avatarPath}` : `/telegram/photos/${avatarPath}`)
    : logoUrl;

  const userName = userData?.first_name ? 
    (userData.last_name ? `${userData.first_name} ${userData.last_name}` : userData.first_name) : 
    t('guest');
  const userUsername = userData?.username ? `@${userData.username}` : '';

  useEffect(() => {
    const img = new Image();
    img.onload = () => {
      setImageLoaded(true);
    };
    img.src = avatarUrl;
  }, [avatarUrl]);

  if (!imageLoaded) return null;

  return (
    <HeaderContainer>
      <div style={{ display: 'flex', alignItems: 'center' }}>
        {hasAvatar ? (
          <Avatar src={avatarUrl} alt="User Avatar" />
        ) : (
          <Logo to="/">
            <Avatar src={logoUrl} alt="Logo" />
          </Logo>
        )}
        <UserInfo>
          <UserName>{userName}</UserName>
          {userUsername && <UserUsername>{userUsername}</UserUsername>}
        </UserInfo>
      </div>

      <ControlsContainer>
        <LanguageSelector ref={languageDropdownRef}>
          <LanguageButton onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}>
            {t('language')}
          </LanguageButton>

          {isLanguageDropdownOpen && (
            <LanguageDropdown>
              <LanguageOption onClick={() => changeLanguage('ru')}>Русский</LanguageOption>
              <LanguageOption onClick={() => changeLanguage('en')}>English</LanguageOption>
            </LanguageDropdown>
          )}
        </LanguageSelector>

        <LocationSelector ref={locationDropdownRef}>
          <LocationButton onClick={() => setIsLocationDropdownOpen(!isLocationDropdownOpen)}>
            {selectedLocation ? `${t('location')}` : t('selectLocation')}
          </LocationButton>

          {isLocationDropdownOpen && (
            <LocationDropdown>
              {loading ? (
                <NoLocationsMessage>{t('loading')}</NoLocationsMessage>
              ) : userLocations.length > 0 ? (
                userLocations.map((location, index) => (
                  <LocationOption
                    key={index}
                    onClick={() => selectLocation(location)}
                  >
                    {`${location.lat.toFixed(4)}, ${location.lon.toFixed(4)}`}
                  </LocationOption>
                ))
              ) : (
                <NoLocationsMessage>{t('noLocations')}</NoLocationsMessage>
              )}
            </LocationDropdown>
          )}
        </LocationSelector>
      </ControlsContainer>
    </HeaderContainer>
  );
};

export default Header;
